<template>
  <div class="chat-shell">
    <header class="topbar">
      <div class="brand"><span class="brand-mark">✦</span><div><div class="brand-title">SuperAI <span>· hive chat</span></div><div class="brand-sub">локальная память → ограниченный поиск</div></div></div>
      <div class="top-actions"><RouterLink class="nav-link" to="/field">Обучение поля</RouterLink><span class="status" :class="mode"><i></i>{{ modeLabel }}</span><button class="ghost" @click="resetHive">Новый улей</button><span class="avatar">AI</span></div>
    </header>

    <main class="workspace">
      <section class="panel chat-panel">
        <div class="panel-head"><div><div class="kicker">CONVERSATION</div><h1>Диалог</h1></div><span class="run-state" :class="{ running: loading }">{{ loading ? 'обработка…' : `${messages.length} сообщений` }}</span></div>
        <div class="messages">
          <article v-for="message in messages" :key="message.id" class="message" :class="message.role"><div class="message-meta"><span>{{ message.role === 'user' ? 'Вы' : 'Улей' }}</span><time>{{ formatTime(message.created_at) }}</time></div><div class="bubble">{{ message.text }}</div></article>
          <div v-if="!messages.length" class="empty-chat">Контекст этого улья сохранится при переходе к обучению поля.</div>
        </div>
        <form class="composer" @submit.prevent="sendMessage"><textarea v-model="draft" rows="3" placeholder="Например: Кот ест рыбу" :disabled="loading"/><div class="composer-foot"><span v-if="error" class="connection-error">{{ error }}</span><span v-else>Улей сначала проверит локальную память</span><button class="send" :disabled="loading || !draft.trim()">{{ loading ? 'Ищу…' : 'Отправить' }}</button></div></form>
      </section>

      <section class="panel field-panel">
        <div class="panel-head"><div><div class="kicker">ROUTING DECISION</div><h2>{{ modeLabel }}</h2></div><span class="run-state" :class="mode">{{ decision?.decision || 'ожидание' }}</span></div>
        <div class="goal-strip"><div class="goal-icon">⌘</div><div><span class="tiny-label">Текущий запрос</span><strong>{{ goalText || 'Отправьте сообщение для активации контекста' }}</strong></div><div v-if="metrics" class="goal-metrics"><span>пчёлы <b>{{ metrics.bees }}</b></span><span>итерации <b>{{ metrics.iterations }}</b></span></div></div>
        <div class="field-wrap">
          <svg class="field-svg" viewBox="0 0 1000 700" role="img" :aria-label="modeLabel">
            <defs><radialGradient id="fieldGlow"><stop stop-color="#78e7d0" stop-opacity=".24"/><stop offset="1" stop-color="#78e7d0" stop-opacity="0"/></radialGradient><filter id="soft"><feGaussianBlur stdDeviation="6"/></filter></defs>
            <circle class="field-ring" cx="500" cy="350" r="245"/><circle class="field-ring ring-2" cx="500" cy="350" r="165"/><circle class="field-ring ring-3" cx="500" cy="350" r="82"/>
            <g v-if="hasSwarmMap" class="swarm-map"><line v-for="source in sources" :key="`flight-${source.id}`" class="flight-line" x1="500" y1="350" :x2="sourcePoint(source).x" :y2="sourcePoint(source).y"/><circle v-for="source in sources" :key="`halo-${source.id}`" class="source-halo" :cx="sourcePoint(source).x" :cy="sourcePoint(source).y" :r="22 + source.fitness * 40"/><g v-for="source in sources" :key="source.id" class="source" :transform="`translate(${sourcePoint(source).x} ${sourcePoint(source).y})`"><circle :r="8 + source.fitness * 14"/><text y="-26" text-anchor="middle">{{ source.label }}</text></g><text v-for="(bee, index) in bees" :key="bee.id" class="bee" :x="470 + (index % 5) * 18" :y="325 + Math.floor(index / 5) * 18">✦</text></g>
            <g v-else-if="hiveGraphNodes.length" class="resonance-map"><line v-for="node in hiveGraphNodes" :key="`line-${node.cell.id}`" x1="500" y1="350" :x2="node.x" :y2="node.y" :class="{ active: activeCellIds.has(node.cell.id) }"/><g v-for="node in hiveGraphNodes" :key="node.cell.id" :class="['resonance-node', { active: activeCellIds.has(node.cell.id) }]" :transform="`translate(${node.x} ${node.y})`" @click="selectedCell = node.cell"><circle :r="node.radius + 11" class="node-halo"/><circle :r="node.radius" class="node-core"/><text text-anchor="middle" y="4">{{ node.label }}</text><text text-anchor="middle" :y="node.radius + 17" class="node-value">{{ percent(node.cell.retention) }}</text></g></g>
            <g class="field-center"><circle cx="500" cy="350" r="34" fill="url(#fieldGlow)"/><circle cx="500" cy="350" r="22"/><text x="500" y="347" text-anchor="middle">{{ hasSwarmMap ? 'РОЙ' : 'УЛЕЙ' }}</text><text x="500" y="361" text-anchor="middle">{{ hasSwarmMap ? 'поиск' : 'резонанс' }}</text></g>
          </svg>
          <div class="field-legend"><span v-if="hasSwarmMap"><i class="dot scout"></i>ограниченный рой</span><span v-else><i class="dot local"></i>локальная активация</span><span><i class="dot nectar"></i>сильный контекст</span></div>
          <div v-if="decision" class="field-caption">{{ decision.external_search_required ? 'Показан только поиск недостающих компонентов.' : 'Внешний поиск пропущен: улей использовал сохранённый контекст.' }}</div>
        </div>
        <div class="event-log"><div class="log-title">Лента решения</div><div v-for="event in eventLog" :key="event.id" class="event"><span class="event-dot" :class="event.kind"></span><span>{{ event.text }}</span><time>{{ event.time }}</time></div><div v-if="!eventLog.length" class="empty-log">События появятся после сообщения</div></div>
      </section>

      <aside class="panel hive-panel">
        <div class="panel-head"><div><div class="kicker">WORKING MEMORY</div><h2>Улей</h2></div><span class="hive-count">{{ cells.length }} / {{ hive?.max_cells || 24 }} ячеек</span></div>
        <div class="hive-summary"><div><span class="tiny-label">Активация</span><strong>{{ percent(averageActivation) }}</strong></div><div><span class="tiny-label">Удержание</span><strong>{{ percent(averageRetention) }}</strong></div></div>
        <div class="hive-map"><svg v-if="hiveGraphNodes.length" class="hive-graph" viewBox="0 0 850 500"><line v-for="link in hiveGraphLinks" :key="link.id" :x1="link.left.x" :y1="link.left.y" :x2="link.right.x" :y2="link.right.y" :stroke-width="1 + link.similarity * 7"/><g v-for="node in hiveGraphNodes" :key="node.cell.id" class="hive-node" :class="{ selected: selectedCell?.id === node.cell.id, active: activeCellIds.has(node.cell.id) }" :transform="`translate(${node.x} ${node.y})`" @click="selectedCell = node.cell"><circle :r="node.radius"/><circle class="node-core" :r="Math.max(10, node.radius - 10)"/><text class="node-label" text-anchor="middle" y="-2">{{ node.label }}</text><text class="node-gravity" text-anchor="middle" y="15">{{ percent(node.cell.retention) }}</text></g></svg><div v-else class="hive-empty">Улей ожидает нектар</div></div>
        <div class="hive-legend"><span><i></i> ячейка памяти</span><span><b></b> общий состав</span></div>
        <section v-if="selectedCell" class="hive-inspector"><div class="inspector-head"><div><span class="tiny-label">Выбранная ячейка</span><strong>{{ selectedCell.label }}</strong></div><button class="ghost" @click="selectedCell = null">×</button></div><div class="node-stats"><span>активация <b>{{ percent(selectedCell.local_activation) }}</b></span><span>удержание <b>{{ percent(selectedCell.retention) }}</b></span></div><div class="component-list"><span v-for="component in selectedCell.components || []" :key="component.id || component.cloud_id" class="component"><span>{{ component.canonical_name }}</span><b>{{ percent(component.composition_share) }}</b></span></div></section>
      </aside>
    </main>
  </div>
</template>

<script setup lang="ts">
import { computed, onMounted, ref, watch } from 'vue'

type Component = { id?: number; cloud_id?: number; canonical_name: string; composition_share: number }
type Cell = { id: string; label: string; x: number; y: number; retention: number; stored_strength: number; local_activation: number; components?: Component[] }
type Message = { id: string; role: 'user' | 'assistant'; text: string; created_at: string }
type Source = { id: string; label: string; x: number; y: number; fitness: number }
type Bee = { id: string }
type Decision = { decision: string; external_search_required: boolean; reasons: string[]; matches: Array<{ cell_id: string; local_support: number }> }

const HIVE_KEY = 'superai-v2-active-hive'
const CHAT_KEY = 'superai-v2-chat-cache'
const hive = ref<Record<string, any> | null>(null)
const cells = ref<Cell[]>([])
const messages = ref<Message[]>([])
const decision = ref<Decision | null>(null)
const metrics = ref<Record<string, number> | null>(null)
const sources = ref<Source[]>([])
const bees = ref<Bee[]>([])
const draft = ref('')
const loading = ref(false)
const error = ref('')
const selectedCell = ref<Cell | null>(null)
const goalText = ref('')

const mode = computed(() => !decision.value ? 'idle' : !decision.value.external_search_required ? 'local' : decision.value.decision === 'PARTIAL_HIT' ? 'partial' : 'external')
const modeLabel = computed(() => mode.value === 'local' ? 'Локальный резонанс' : mode.value === 'partial' ? 'Частичный поиск' : mode.value === 'external' ? 'Внешний поиск' : 'Улей готов')
const hasSwarmMap = computed(() => Boolean(decision.value?.external_search_required && sources.value.length))
const activeCellIds = computed(() => new Set((decision.value?.matches || []).map(match => match.cell_id)))
const averageActivation = computed(() => cells.value.length ? cells.value.reduce((sum, cell) => sum + cell.local_activation, 0) / cells.value.length : 0)
const averageRetention = computed(() => cells.value.length ? cells.value.reduce((sum, cell) => sum + cell.retention, 0) / cells.value.length : 0)
const hiveGraphNodes = computed(() => cells.value.map((cell, index) => ({ cell, x: 105 + ((cell.x || index * 73) % 650), y: 90 + ((cell.y || index * 107) % 330), radius: 24 + cell.retention * 24, label: cell.label.slice(0, 14) })))
const hiveGraphLinks = computed(() => { const links: Array<{ id: string; left: typeof hiveGraphNodes.value[number]; right: typeof hiveGraphNodes.value[number]; similarity: number }> = []; const nodes = hiveGraphNodes.value; for (let left = 0; left < nodes.length; left++) for (let right = left + 1; right < nodes.length; right++) { const similarity = compositionSimilarity(nodes[left].cell.components || [], nodes[right].cell.components || []); if (similarity >= .18) links.push({ id: `${nodes[left].cell.id}-${nodes[right].cell.id}`, left: nodes[left], right: nodes[right], similarity }) } return links })
const eventLog = computed(() => { if (!decision.value) return []; const now = formatTime(new Date().toISOString()); const events = [{ id: 'route', kind: 'goal', text: `Маршрутизатор: ${decision.value.decision}`, time: now }]; if (decision.value.external_search_required) events.push({ id: 'search', kind: 'bee', text: `Рой получил ${metrics.value?.bees || 0} пчёл для недостающего контекста`, time: now }); else events.push({ id: 'local', kind: 'done', text: `Активировано ${metrics.value?.activated_cells || 0} ячеек без внешнего поиска`, time: now }); if ((metrics.value?.merged_cells || 0) > 0) events.push({ id: 'merge', kind: 'nectar', text: 'Новый нектар объединён с локальной памятью', time: now }); return events })

function percent(value: number) { return `${Math.round((value || 0) * 100)}%` }
function formatTime(value: string) { return new Date(value).toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' }) }
function sourcePoint(source: Source) { return { x: 105 + (Math.abs(source.x || 0) % 790), y: 95 + (Math.abs(source.y || 0) % 510) } }
function compositionSimilarity(left: Component[], right: Component[]) { const leftMap = new Map(left.map(item => [item.cloud_id || item.id || 0, item.composition_share])); const rightMap = new Map(right.map(item => [item.cloud_id || item.id || 0, item.composition_share])); let overlap = 0; for (const [key, value] of leftMap) overlap += Math.min(value, rightMap.get(key) || 0); return overlap }
async function api(path: string, options?: RequestInit) { const response = await fetch(path, { headers: { 'Content-Type': 'application/json' }, ...options }); if (!response.ok) throw new Error(await response.text()); return response.json() }
function cacheState() { if (!hive.value) return; localStorage.setItem(HIVE_KEY, hive.value.id); localStorage.setItem(CHAT_KEY, JSON.stringify({ messages: messages.value, goalText: goalText.value, decision: decision.value, metrics: metrics.value, sources: sources.value, bees: bees.value })) }
function applyState(state: any, preserveMessages = true) { hive.value = state.hive; cells.value = state.cells || []; if (!preserveMessages && state.messages?.length) messages.value = state.messages.map((message: any) => ({ ...message, role: 'user' as const })); if (selectedCell.value) selectedCell.value = cells.value.find(cell => cell.id === selectedCell.value?.id) || null }
async function createHive() { const state = await api('/api/v2/hives', { method: 'POST', body: JSON.stringify({ max_cells: 24 }) }); applyState(state, false); cacheState() }
async function restoreHive() { const id = localStorage.getItem(HIVE_KEY); const cache = localStorage.getItem(CHAT_KEY); if (cache) { try { const value = JSON.parse(cache); messages.value = value.messages || []; goalText.value = value.goalText || ''; decision.value = value.decision || null; metrics.value = value.metrics || null; sources.value = value.sources || []; bees.value = value.bees || [] } catch { localStorage.removeItem(CHAT_KEY) } } if (!id) return createHive(); try { const state = await api(`/api/v2/hives/${id}`); applyState(state, messages.value.length > 0); if (!messages.value.length && state.messages?.length) applyState(state, false) } catch { localStorage.removeItem(HIVE_KEY); return createHive() } }
async function sendMessage() { const text = draft.value.trim(); if (!text || loading.value || !hive.value) return; loading.value = true; error.value = ''; const now = new Date().toISOString(); messages.value.push({ id: `user-${Date.now()}`, role: 'user', text, created_at: now }); draft.value = ''; goalText.value = text; cacheState(); try { const result = await api(`/api/v2/hives/${hive.value.id}/query`, { method: 'POST', body: JSON.stringify({ text }) }); applyState(result); decision.value = result.decision; metrics.value = result.metrics || null; sources.value = result.external_search?.sources || []; bees.value = result.external_search?.bees || []; messages.value.push({ id: `assistant-${result.message_id}`, role: 'assistant', text: result.decision.external_search_required ? `Улей активировал известные компоненты и выполнил ${result.decision.decision === 'PARTIAL_HIT' ? 'частичный' : 'целевой'} внешний поиск.` : 'Контекст найден в локальной памяти: внешний поиск не запускался.', created_at: new Date().toISOString() }) } catch (cause) { error.value = 'Не удалось обработать сообщение. Проверьте сервер.'; messages.value.pop() } finally { loading.value = false; cacheState() } }
async function resetHive() { localStorage.removeItem(HIVE_KEY); localStorage.removeItem(CHAT_KEY); messages.value = []; decision.value = null; metrics.value = null; sources.value = []; bees.value = []; selectedCell.value = null; goalText.value = ''; await createHive() }
watch([messages, cells, decision, metrics, sources], cacheState, { deep: true })
onMounted(() => { void restoreHive() })
</script>

<style scoped lang="scss">
